use std::collections::HashMap;

struct KeyValueStore {
    data: HashMap<String, i32>,
}

impl KeyValueStore {
    fn new() -> Self {
        KeyValueStore { data: HashMap::new() }
    }

    fn insert(&mut self, key: String, value: i32) {
        self.data.insert(key, value);
    }

    fn process_map_expression(&self, input_value: i32) -> i32 {
        input_value * 2 + 1
    }

    fn process_reduce_expression(&self, first_result: i32, second_result: i32) -> i32 {
        first_result.max(second_result)
    }

    fn run_job(&mut self) -> i32 {
        let initial_value = 10;
        let mapped_value = self.process_map_expression(initial_value);

        self.insert("A".to_string(), 5);
        let reduced_result = self.process_reduce_expression(mapped_value, 20);

        reduced_result
    }
}

fn main() {
    let mut store = KeyValueStore::new();
    let final_output = store.run_job();
    println!("Final computed result: {}", final_output);
}

