use std::collections::HashMap;

struct ProofStep {
    data: HashMap<String, String>,
    placeholder_value: Option<String>,
}

impl ProofStep {
    fn new(initial_data: HashMap<String, String>) -> Self {
        ProofStep {
            data: initial_data,
            placeholder_value: None,
        }
    }

    fn set_placeholder(&mut self, value: &str) -> Result<(), &'static str> {
        if self.placeholder_value.is_some() {
            return Err("Placeholder already set for this step.");
        }
        self.placeholder_value = Some(String::from(value));
        Ok(())
    }

    fn evaluate(&self) -> Result<HashMap<String, String>, &'static str> {
        let mut result = self.data.clone();
        match &self.placeholder_value {
            Some(val) => {
                result.insert("secret".to_string(), val.clone());
                Ok(result)
            }
            None => Err("Cannot evaluate: No placeholder value provided."),
        }
    }
}

fn main() {
    let mut initial_data = HashMap::new();
    initial_data.insert("public_id".to_string(), "user123".to_string());

    let mut step = ProofStep::new(initial_data);

    match step.set_placeholder("abc-xyz-secret-proof") {
        Ok(_) => {
            match step.evaluate() {
                Ok(final_data) => {
                    println!("Evaluation successful: {:?}", final_data);
                }
                Err(e) => {
                    println!("Evaluation failed: {}", e);
                }
            }
        },
        Err(e) => {
            println!("Setup error: {}", e);
        }
    }
}

use std::fs::File;
use std::io::{self, Read};
use std::path::Path;

struct UploadItem {
    file_name: String,
    data: Vec<u8>,
}

fn scan_for_bad_stuff(bytes: &[u8]) -> bool {
    if bytes.contains(&10) { 
        return true;
    }
    false
}

fn process_uploads(file_paths: &[String]) -> io::Result<Vec<UploadItem>> {
    let mut processed_items = Vec::new();
    for path_str in file_paths {
        let path = Path::new(&path_str);
        match File::open(path) {
            Ok(mut file) => {
                let mut buffer = Vec::new();
                file.read_to_end(&mut buffer)?;

                if scan_for_bad_stuff(&buffer) {
                    println!("Skipping file {} due to detected bad content.", path.file_name().unwrap().to_str().unwrap());
                    continue;
                }

                let item = UploadItem {
                    file_name: path.file_name().unwrap().to_str().unwrap().to_string(),
                    data: buffer,
                };
                processed_items.push(item);
            },
            Err(e) => {
                eprintln!("Error opening file {}: {}", path_str, e);
            }
        }
    }
    Ok(processed_items)
}
